import React from "react";
import { useNavigate } from "react-router-dom";
import Header from "./dashboard/Header";
import Card from "./dashboard/Card";
import Activity from "./dashboard/Activity";
import Peers from "./dashboard/Peers";

const Dashboard = () => {
  const navigate = useNavigate(); // Hook for navigation

  return (
    <div className="dashboard">
      {/* Header */}
      <Header />

      {/* Stats Section */}
      <div className="stats grid grid-cols-2 md:grid-cols-4 gap-4 p-4">
        <Card title="Active Collaborations" count="3" icon="👥" />
        <Card title="Study Groups" count="2" icon="📖" />

        {/* Projects Button - Redirects to project.js */}
        <button
          onClick={() => navigate("/project")}
          className="flex flex-col items-center justify-center bg-blue-600 text-white p-4 rounded-lg shadow-md hover:bg-blue-700 transition"
        >
          <span className="text-2xl">🎯</span>
          <span className="font-semibold">Projects</span>
          <span className="text-lg">4</span>
        </button>

        <Card title="Queries Written" count="5" icon="📅" />
      </div>

      {/* Main Section */}
      <div className="main-section flex flex-col md:flex-row gap-4 p-4">
        <Activity />
        <Peers />
      </div>
    </div>
  );
};

export default Dashboard;
